        'contents_and_confidentiality' => [
            'title'       => '11.- CONTENTS AND CONFIDENTIALITY',
            'sub_title_1' => 'CONFIDENTIAL INFORMATION',
            'text_line_1' => '"Confidential Information" means any information or data, whether or not collected in written, computerized or any other existing support or that could be invented in thes',
            'text_line_2' => 'future, that LimaTours communicates or provides to the CLIENT, or to which the CLIENT has access with or without knowledge and / or express consent of LimaTours.',

